const cityToIATA = {
  // India
  "new delhi": "DEL",
  "delhi": "DEL",
  "mumbai": "BOM",
  "bangalore": "BLR",
  "chennai": "MAA",
  "kolkata": "CCU",
  "hyderabad": "HYD",
  "pune": "PNQ",
  "ahmedabad": "AMD",
  "jaipur": "JAI",
  "goa": "GOI",

  // Sri Lanka - all map to CMB
  "sri lanka": "CMB",
  "colombo": "CMB",
  "matara": "CMB",
  "jaffna": "CMB",
  "kandy": "CMB",
  "galle": "CMB",
  "negombo": "CMB",
  "trincomalee": "CMB",

  // Australia
  "perth": "PER",
  "sydney": "SYD",
  "melbourne": "MEL",
  "brisbane": "BNE",

  // Other major cities
  "singapore": "SIN",
  "kuala lumpur": "KUL",
  "bangkok": "BKK",
  "dubai": "DXB",
  "london": "LHR",
  "new york": "JFK",
  "los angeles": "LAX"
};

function getIATACode(location) {
  if (!location) return null;

  const normalized = location.toLowerCase().trim();

  // Check if already an IATA code (3 uppercase letters)
  if (/^[A-Z]{3}$/.test(location)) {
    return location;
  }

  // Look up in mapping
  return cityToIATA[normalized] || null;
}

const data = $input.first().json.output;

const originCode = getIATACode(data.origin);
const destinationCode = getIATACode(data.destination);

return {
  ...data,
  origin_code: originCode,
  destination_code: destinationCode
};

